import React from 'react';

interface Customer {
    id: string;
    name: string;
    email: string;
}

const mockCustomers: Customer[] = [
    { id: '1', name: 'Cliente Exemplo 1', email: 'cliente1@provedor.com' },
    { id: '2', name: 'Cliente Exemplo 2', email: 'cliente2@provedor.com' },
];

const Customers: React.FC = () => {
    return (
        <div style={{ padding: '1rem' }}>
            <h1>Clientes</h1>
            <p>Lista simples de exemplo, depois vamos integrar com o backend.</p>
            <table>
                <thead>
                    <tr>
                        <th>ID</th>
                        <th>Nome</th>
                        <th>Email</th>
                    </tr>
                </thead>
                <tbody>
                    {mockCustomers.map((customer) => (
                        <tr key={customer.id}>
                            <td>{customer.id}</td>
                            <td>{customer.name}</td>
                            <td>{customer.email}</td>
                        </tr>
                    ))}
                </tbody>
            </table>
        </div>
    );
};

export default Customers;
